const config = $('Normalize Lazada Token Set').first().json;
const pagePath = '/orders/get';
const now = new Date();
const updateBefore = now.toISOString().slice(0, 19) + '+07:00';
const updateAfterDate = new Date(now.getTime() - Number(config.lookbackDays || '3') * 24 * 60 * 60 * 1000);
const updateAfter = updateAfterDate.toISOString().slice(0, 19) + '+07:00';
const timestamp = Date.now().toString();
const params = {
  access_token: config.accessToken,
  app_key: config.appKey,
  limit: '100',
  offset: '0',
  sign_method: 'sha256',
  sort_direction: 'DESC',
  timestamp,
  update_after: updateAfter,
  update_before: updateBefore
};
const sortedKeys = Object.keys(params).sort();
const concatenated = sortedKeys.map((key) => key + params[key]).join('');
const sign = hmacSha256(config.appSecret, pagePath + concatenated);
const query = sortedKeys.map((key) => `${encodeURIComponent(key)}=${encodeURIComponent(params[key])}`).join('&');
const requestUrl = `${config.lazadaApiBase}${pagePath}?${query}&sign=${sign}`;

return [{
  json: {
    ...config,
    ordersRequestUrl: requestUrl,
    updateAfter,
    updateBefore
  }
}];

const config = $('Normalize Lazada Token Set').first().json;
const response = $input.first().json;
const data = response.data || response.result?.data || response.result || response;
const orders = Array.isArray(data?.orders)
  ? data.orders
  : Array.isArray(data)
    ? data
    : Array.isArray(data?.order_list)
      ? data.order_list
      : [];

if (!Array.isArray(orders) || orders.length === 0) {
  return [];
}

function pickBuyerName(order) {
  const shipping = order.address_shipping || order.shipping_address || {};
  const fromOrder = [order.customer_first_name, order.customer_last_name].filter(Boolean).join(' ').trim();
  const fromShipping = [shipping.first_name, shipping.last_name].filter(Boolean).join(' ').trim();
  return fromOrder || fromShipping || order.customer_name || order.buyer_name || null;
}

return orders.map((order) => {
  const platformOrderId = String(order.order_id || order.orderId || '').trim();
  if (!platformOrderId) {
    return null;
  }

  const body = {
    store_id: config.storeId,
    platform_order_id: platformOrderId,
    barcode_value: platformOrderId,
    buyer_name: pickBuyerName(order),
    items_json: [],
    awb_status: 'pending'
  };

  return {
    json: {
      ...body,
      supabaseUrl: config.supabaseUrl,
      serviceRoleKey: config.serviceRoleKey,
      requestUrl: `${config.supabaseUrl}/rest/v1/orders?on_conflict=store_id,platform_order_id`,
      requestBody: JSON.stringify(body)
    }
  };
}).filter(Boolean);
